// 对长文档进行编号校对（标题、图、表、公式编号）
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;
var totalParagraphs = paragraphs.Count;
var issues = [];
var fixedCount = 0;

// 扫描文档结构
var structure = {
  headings: [],
  figures: [],
  tables: [],
  formulas: []
};

// 扫描标题
for (var i = 1; i <= totalParagraphs; i++) {
  var para = paragraphs.Item(i);
  var text = para.Range.Text.trim();
  if (text.length === 0) continue;

  // 判断标题级别
  var headingLevel = 0;
  var styleName = para.Style.NameLocal;
  if (styleName.indexOf("标题 1") === 0 || styleName === "Heading 1") headingLevel = 1;
  else if (styleName.indexOf("标题 2") === 0 || styleName === "Heading 2") headingLevel = 2;
  else if (styleName.indexOf("标题 3") === 0 || styleName === "Heading 3") headingLevel = 3;
  else if (styleName.indexOf("标题 4") === 0 || styleName === "Heading 4") headingLevel = 4;

  if (headingLevel > 0) {
    structure.headings.push({
      index: i,
      level: headingLevel,
      text: text,
      range: para.Range
    });
  }

  // 扫描图编号
  if (text.indexOf("图") === 0 || text.indexOf("图 ") === 0) {
    structure.figures.push({
      index: i,
      text: text,
      range: para.Range
    });
  }

  // 扫描表编号
  if (text.indexOf("表") === 0 || text.indexOf("表 ") === 0) {
    structure.tables.push({
      index: i,
      text: text,
      range: para.Range
    });
  }

  // 扫描公式编号
  if (text.indexOf("(") === 0 && text.indexOf(")") > 0 && text.indexOf("-") > 0) {
    structure.formulas.push({
      index: i,
      text: text,
      range: para.Range
    });
  }
}

// 分析标题编号连续性
var chapterCount = 0;
var sectionCount = 0;
var subsectionCount = 0;
var subsubsectionCount = 0;

for (var i = 0; i < structure.headings.length; i++) {
  var heading = structure.headings[i];
  var text = heading.text;
  var match;

  if (heading.level === 1) {
    // 一级标题
    chapterCount++;
    match = text.match(/^(\d+)\s+(.+)$/) || text.match(/^第(\d+)章\s+(.+)$/);
    if (match) {
      var currentNum = parseInt(match[1]);
      if (currentNum !== chapterCount) {
        issues.push({
          type: "heading",
          level: 1,
          index: heading.index,
          original: text,
          suggested: chapterCount + " " + match[2],
          rule: "N-002"
        });
      }
    }
    sectionCount = 0; // 重置二级标题计数
    subsectionCount = 0; // 重置三级标题计数
    subsubsectionCount = 0; // 重置四级标题计数
  } else if (heading.level === 2) {
    // 二级标题
    sectionCount++;
    match = text.match(/^(\d+)\.(\d+)\s+(.+)$/);
    if (match) {
      var currentChapter = parseInt(match[1]);
      var currentSection = parseInt(match[2]);
      if (currentChapter !== chapterCount || currentSection !== sectionCount) {
        issues.push({
          type: "heading",
          level: 2,
          index: heading.index,
          original: text,
          suggested: chapterCount + "." + sectionCount + " " + match[3],
          rule: "N-003"
        });
      }
    }
    subsectionCount = 0; // 重置三级标题计数
    subsubsectionCount = 0; // 重置四级标题计数
  } else if (heading.level === 3) {
    // 三级标题
    subsectionCount++;
    match = text.match(/^(\d+)\.(\d+)\.(\d+)\s+(.+)$/);
    if (match) {
      var currentChapter = parseInt(match[1]);
      var currentSection = parseInt(match[2]);
      var currentSubsection = parseInt(match[3]);
      if (currentChapter !== chapterCount || currentSection !== sectionCount || currentSubsection !== subsectionCount) {
        issues.push({
          type: "heading",
          level: 3,
          index: heading.index,
          original: text,
          suggested: chapterCount + "." + sectionCount + "." + subsectionCount + " " + match[4],
          rule: "N-004"
        });
      }
    }
    subsubsectionCount = 0; // 重置四级标题计数
  } else if (heading.level === 4) {
    // 四级标题
    subsubsectionCount++;
    match = text.match(/^(\d+)\.(\d+)\.(\d+)\.(\d+)\s+(.+)$/);
    if (match) {
      var currentChapter = parseInt(match[1]);
      var currentSection = parseInt(match[2]);
      var currentSubsection = parseInt(match[3]);
      var currentSubsubsection = parseInt(match[4]);
      if (currentChapter !== chapterCount || currentSection !== sectionCount || currentSubsection !== subsectionCount || currentSubsubsection !== subsubsectionCount) {
        issues.push({
          type: "heading",
          level: 4,
          index: heading.index,
          original: text,
          suggested: chapterCount + "." + sectionCount + "." + subsectionCount + "." + subsubsectionCount + " " + match[5],
          rule: "N-005"
        });
      }
    }
  }
}

